import zipfile
import xml.etree.ElementTree as ET

# xlsx is a zip file, let's extract the shared strings and sheet data
with zipfile.ZipFile('interview_survey_final.xlsx', 'r') as z:
    # Read shared strings
    with z.open('xl/sharedStrings.xml') as f:
        tree = ET.parse(f)
        root = tree.getroot()
        ns = {'main': 'http://schemas.openxmlformats.org/spreadsheetml/2006/main'}
        strings = []
        for si in root.findall('.//main:si', ns):
            text = ''
            for t in si.findall('.//main:t', ns):
                text += t.text or ''
            strings.append(text)

    # Read sheet data
    with z.open('xl/worksheets/sheet1.xml') as f:
        tree = ET.parse(f)
        root = tree.getroot()
        ns = {'main': 'http://schemas.openxmlformats.org/spreadsheetml/2006/main'}
        rows = []
        for row in root.findall('.//main:row', ns):
            cells = []
            for cell in row.findall('main:c', ns):
                cell_type = cell.get('t')
                cell_ref = cell.get('r')
                v = cell.find('main:v', ns)
                if v is not None:
                    if cell_type == 's':
                        cells.append(strings[int(v.text)])
                    else:
                        cells.append(v.text)
                else:
                    cells.append('')
            rows.append(cells)

        for row in rows:
            print(row)
EOF"}

